async def is_breached_password(password: str) -> bool:
    # Have I Been Pwned k-anonymity API.
    # Sends only first 5 SHA-1 hex chars, never the password.
    import hashlib

    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]

    try:
        async with httpx.AsyncClient(timeout=3.0) as client:
            response = await client.get(
                f"https://api.pwnedpasswords.com/range/{prefix}",
                headers={"Add-Padding": "true", "User-Agent": "registration-validation"},
            )
            if response.status_code != 200:
                return False

            for line in response.text.splitlines():
                candidate, _, count = line.partition(":")
                if secrets.compare_digest(candidate, suffix):
                    return int(count or "0") > 0
    except Exception:
        # Do not block registration because an external service is unavailable.
        return False

    return False


async def validate_password(
    raw: Any,
    email: str | None,
    username: str | None,
    display_name: str | None,
    errors: list[dict[str, str]],
) -> str | None:
    if not isinstance(raw, str):
        add_error(errors, "password", "type", "Password must be a string.")
        return None

    password = normalize_unicode(raw)

    if not password:
        add_error(errors, "password", "required", "Password is required.")
        return None

    if len(password) < PASSWORD_MIN_LEN:
        add_error(errors, "password", "too_short", "Password must be at least 12 characters.")

    if len(password) > PASSWORD_MAX_LEN:
        add_error(errors, "password", "too_long", "Password is too long.")

    if CONTROL_RE.search(password):
        add_error(errors, "password", "control_chars", "Password contains invalid control characters.")

    if password.strip() != password:
        add_error(errors, "password", "surrounding_whitespace", "Password must not start or end with whitespace.")

    classes = {
        "lowercase": bool(re.search(r"[a-z]", password)),
        "uppercase": bool(re.search(r"[A-Z]", password)),
        "digit": bool(re.search(r"\d", password)),
        "symbol": bool(re.search(r"[^A-Za-z0-9\s]", password)),
    }
    if sum(classes.values()) < 3:
        add_error(errors, "password", "complexity", "Password must include at least 3 character classes.")

    if REPEATED_CHAR_RE.search(password):
        add_error(errors, "password", "repeated_chars", "Password contains too many repeated characters.")

    if SEQUENTIAL_RE.search(password):
        add_error(errors, "password", "sequence", "Password contains a common sequence.")

    lowered = password.casefold()
    common_passwords = {
        "password", "password1", "password123", "qwerty123", "admin123",
        "letmein", "welcome", "iloveyou", "monkey", "dragon",
    }
    if lowered in common_passwords:
        add_error(errors, "password", "common", "Password is too common.")

    if username and username.casefold() in lowered:
        add_error(errors, "password", "contains_username", "Password must not contain the username.")

    if email:
        local_part = email.split("@", 1)[0].casefold()
        domain = email.split("@", 1)[1].split(".", 1)[0].casefold()
        if local_part and local_part in lowered:
            add_error(errors, "password", "contains_email", "Password must not contain the email local part.")
        if domain and len(domain) >= 4 and domain in lowered:
            add_error(errors, "password", "contains_email_domain", "Password must not contain the email domain.")

    if display_name:
        compact_display = re.sub(r"\s+", "", html.unescape(display_name)).casefold()
        if len(compact_display) >= 4 and compact_display in lowered:
            add_error(errors, "password", "contains_display_name", "Password must not contain the display name.")

    if await is_breached_password(password):
        add_error(errors, "password", "breached", "Password has appeared in known data breaches.")

    return password


